8. namespace ContosoUniversity.Controllers
9. {
10.     public abstract class BaseController : Controller
11.     {
12.         protected SchoolContext db;
13.         protected NotificationService notificationService = new NotificationService();
14. 
15.         public BaseController(SchoolContext context)
16.         {
17.             db = context;
18.         }
19. 
20.         protected void SendEntityNotification(string entityType, string entityId, EntityOperation operation)
21.         {
22.             SendEntityNotification(entityType, entityId, null, operation);
23.         }
24. 
25.         protected void SendEntityNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
26.         {
27.             try
28.             {
29.                 var userName = "System"; // No authentication, use System as default user
30.                 notificationService.SendNotification(entityType, entityId, entityDisplayName, operation, userName);
31.             }
32.             catch (Exception ex)
33.             {
34.                 // Log the error but don't break the main operation
35.                 System.Diagnostics.Debug.WriteLine($"Failed to send notification: {ex.Message}");
36.             }
37.         }
38. 
39.         protected override void Dispose(bool disposing)
40.         {
41.             if (disposing)
42.             {
43.                 db?.Dispose();
44.                 notificationService?.Dispose();
45.             }
46.             base.Dispose(disposing);
47.         }
48.     }
49. }
